      subtype: 'success',
      total_cost_usd: 0.01,
      usage: { input_tokens: 100 },
      model: 'claude-opus-4-7',
    } as unknown as SDKMessage;

    const events = [];
    for await (const ev of mapSdkMessage(result, fakeSession(), 'sess-1', emptyToolState())) {
